"use client"

import * as React from "react"
import {
  Alert,
  AlertTitle,
  AlertDescription,
  AmountBreakdown,
  Badge,
  Banner,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  MetadataList,
  NumberInput,
  Separator,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  Stepper,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  type StepperStep,
  type AmountLine,
} from "@gunjo/ui"
import {
  IconPlane,
  IconArmchair2,
  IconLuggage,
  IconClock,
  IconShieldCheck,
  IconDoorEnter,
  IconUsers,
} from "@tabler/icons-react"

import {
  FLIGHT,
  PASSENGERS,
  SEAT_TYPE_LABEL,
  colWindowLabel,
  seatById,
  yen,
  type Passenger,
} from "./data"
import { SeatMap } from "./SeatMap"
import { BoardingPass } from "./BoardingPass"

type StepKey = "confirm" | "seat" | "baggage" | "pass"

const STEP_ORDER: StepKey[] = ["confirm", "seat", "baggage", "pass"]
const STEP_LABEL: Record<StepKey, string> = {
  confirm: "確認",
  seat: "座席",
  baggage: "手荷物",
  pass: "搭乗券",
}

const BAG_FEE_PER_EXTRA = 1000 // 個数超過1個あたり（モック）

export default function FlightCheckinPage() {
  const [step, setStep] = React.useState<StepKey>("confirm")
  const [passengers, setPassengers] = React.useState<Passenger[]>(PASSENGERS)
  const [checkedIn, setCheckedIn] = React.useState(false)

  // 受託手荷物（搭乗者ごと）
  const [bags, setBags] = React.useState<Record<string, number>>(
    () => Object.fromEntries(PASSENGERS.map((p) => [p.id, 1])),
  )

  // 座席変更シート
  const [seatSheetFor, setSeatSheetFor] = React.useState<Passenger | null>(null)
  const [draftSeat, setDraftSeat] = React.useState<string | null>(null)

  // 搭乗券タブで表示中の搭乗者
  const [passIndex, setPassIndex] = React.useState(0)

  const stepIndex = STEP_ORDER.indexOf(step)

  const stepperSteps: StepperStep[] = STEP_ORDER.map((key, i) => ({
    label: STEP_LABEL[key],
    state: i < stepIndex ? "completed" : i === stepIndex ? "current" : "upcoming",
  }))

  // ── 料金集計 ──────────────────────────────────────────────
  const ownSeats = passengers.map((p) => p.seat)

  const seatFeeTotal = passengers.reduce((sum, p) => {
    const s = seatById(p.seat)
    return sum + (s ? s.fee : 0)
  }, 0)

  const freeBagsPerPax = 1
  const extraBags = Object.values(bags).reduce(
    (sum, n) => sum + Math.max(0, n - freeBagsPerPax),
    0,
  )
  const bagFeeTotal = extraBags * BAG_FEE_PER_EXTRA

  const amountLines: AmountLine[] = [
    { type: "heading", label: "座席指定料" },
    ...passengers.map((p) => {
      const s = seatById(p.seat)
      const fee = s ? s.fee : 0
      return {
        label: `${p.name}（${p.seat}）`,
        note: s ? `${SEAT_TYPE_LABEL[s.type]}・${colWindowLabel(p.seat)}` : undefined,
        amount: fee,
      } as AmountLine
    }),
    { type: "heading", label: "受託手荷物" },
    {
      label: "無料受託手荷物",
      note: `お一人さま ${freeBagsPerPax} 個まで無料`,
      amount: 0,
    },
    {
      label: "超過個数",
      note: `${extraBags} 個 × ${yen(BAG_FEE_PER_EXTRA)}`,
      amount: bagFeeTotal,
    },
  ]

  const grandTotal = seatFeeTotal + bagFeeTotal

  // ── 座席変更フロー ────────────────────────────────────────
  function openSeatSheet(p: Passenger) {
    setSeatSheetFor(p)
    setDraftSeat(p.seat)
  }
  function confirmSeatChange() {
    if (!seatSheetFor || !draftSeat) return
    setPassengers((prev) =>
      prev.map((p) => (p.id === seatSheetFor.id ? { ...p, seat: draftSeat } : p)),
    )
    setSeatSheetFor(null)
    setDraftSeat(null)
  }

  function goNext() {
    const next = STEP_ORDER[Math.min(stepIndex + 1, STEP_ORDER.length - 1)]
    if (next === "pass") setCheckedIn(true)
    setStep(next)
    if (typeof window !== "undefined") window.scrollTo({ top: 0 })
  }
  function goBack() {
    setStep(STEP_ORDER[Math.max(stepIndex - 1, 0)])
  }

  return (
    <main className="mx-auto w-full max-w-md px-4 pb-28 pt-5 sm:max-w-lg">
      {/* ヘッダ */}
      <header className="mb-4">
        <div className="flex items-center justify-between">
          <h1 className="text-lg font-bold">オンラインチェックイン</h1>
          <Badge variant="outline" icon={<IconPlane className="h-3.5 w-3.5" />}>
            {FLIGHT.carrierName}
          </Badge>
        </div>
        <p className="mt-0.5 text-sm text-muted-foreground">
          予約番号 <span className="font-mono font-medium text-foreground">{FLIGHT.pnr}</span>
        </p>
      </header>

      {/* 手続きの流れ */}
      <div className="mb-5">
        <Stepper steps={stepperSteps} aria-label="チェックインの手続きの流れ" />
      </div>

      {/* ───────── 確認 ───────── */}
      {step === "confirm" && (
        <section aria-labelledby="confirm-h" className="flex flex-col gap-4">
          <h2 id="confirm-h" className="sr-only">予約・便の確認</h2>

          <Banner variant="info" icon={<IconClock className="h-4 w-4" />}>
            <span>
              <strong>搭乗開始 {FLIGHT.boardingTime}</strong> ／ {FLIGHT.terminal}・搭乗口 {FLIGHT.gate}。保安検査は {FLIGHT.securityClose} までにお済ませください。
            </span>
          </Banner>

          {/* 便サマリ */}
          <Card>
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle as="h2" className="text-base">{FLIGHT.flightNo}</CardTitle>
                <Badge variant="secondary">{FLIGHT.date}</Badge>
              </div>
            </CardHeader>
            <CardContent className="pt-0">
              <div className="flex items-center justify-between">
                <div>
                  <div className="text-2xl font-bold leading-none">{FLIGHT.depCode}</div>
                  <div className="text-xs text-muted-foreground">{FLIGHT.depName}</div>
                  <div className="mt-1 text-lg font-semibold">{FLIGHT.std}</div>
                </div>
                <div className="flex flex-col items-center text-muted-foreground">
                  <IconPlane className="h-5 w-5 rotate-90" aria-hidden />
                  <span className="text-[11px]">{FLIGHT.aircraft}</span>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-bold leading-none">{FLIGHT.arrCode}</div>
                  <div className="text-xs text-muted-foreground">{FLIGHT.arrName}</div>
                  <div className="mt-1 text-lg font-semibold">{FLIGHT.sta}</div>
                </div>
              </div>

              <Separator className="my-4" />

              <MetadataList
                items={[
                  { label: "区間", value: `${FLIGHT.depName} → ${FLIGHT.arrName}` },
                  { label: "機材", value: FLIGHT.aircraft },
                  { label: "ターミナル", value: FLIGHT.terminal },
                  { label: "搭乗口 / ゲート", value: FLIGHT.gate },
                  { label: "保安検査 締切", value: FLIGHT.securityClose },
                ]}
              />
            </CardContent>
          </Card>

          {/* 同行者 */}
          <Card>
            <CardHeader className="pb-2">
              <div className="flex items-center gap-2">
                <IconUsers className="h-4 w-4 text-muted-foreground" aria-hidden />
                <CardTitle as="h2" className="text-base">搭乗者 {passengers.length} 名</CardTitle>
              </div>
            </CardHeader>
            <CardContent className="flex flex-col gap-2 pt-0">
              {passengers.map((p) => (
                <div
                  key={p.id}
                  className="flex items-center justify-between gap-2 rounded-md border bg-card px-3 py-2"
                >
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="truncate font-medium">{p.name}</span>
                      <Badge variant={p.kind === "child" ? "info" : "outline"}>
                        {p.kind === "child" ? "小児" : "大人"}
                      </Badge>
                      {p.priority && <Badge variant="success">優先搭乗</Badge>}
                    </div>
                    <div className="truncate text-xs text-muted-foreground">{p.kana}</div>
                  </div>
                  <Badge variant="secondary" className="shrink-0">{p.seat}</Badge>
                </div>
              ))}
            </CardContent>
          </Card>
        </section>
      )}

      {/* ───────── 座席 ───────── */}
      {step === "seat" && (
        <section aria-labelledby="seat-h" className="flex flex-col gap-4">
          <h2 id="seat-h" className="text-base font-semibold">座席の確認・変更</h2>
          <p className="text-sm text-muted-foreground">
            搭乗者ごとに座席を変更できます。座席表から空席をお選びください。
          </p>

          {passengers.map((p) => {
            const s = seatById(p.seat)
            return (
              <Card key={p.id}>
                <CardContent className="flex items-center justify-between gap-3 p-4">
                  <div className="flex items-center gap-3">
                    <div className="flex h-11 w-11 shrink-0 flex-col items-center justify-center rounded-lg border bg-muted/40">
                      <IconArmchair2 className="h-4 w-4 text-muted-foreground" aria-hidden />
                      <span className="text-xs font-bold">{p.seat}</span>
                    </div>
                    <div className="min-w-0">
                      <div className="truncate font-medium">{p.name}</div>
                      <div className="text-xs text-muted-foreground">
                        {s ? `${SEAT_TYPE_LABEL[s.type]}・${colWindowLabel(p.seat)}` : "—"}
                        {s && s.fee > 0 ? ` ・ ${yen(s.fee)}` : ""}
                      </div>
                    </div>
                  </div>
                  <Button variant="outline" size="sm" onClick={() => openSeatSheet(p)}>
                    変更
                  </Button>
                </CardContent>
              </Card>
            )
          })}

          <Alert variant="info">
            <AlertTitle>足元ゆったり席・非常口座席について</AlertTitle>
            <AlertDescription>
              非常口座席は、緊急時に乗務員の援助ができる方のみご利用いただけます。15歳未満のお客さまはご指定いただけません。
            </AlertDescription>
          </Alert>
        </section>
      )}

      {/* ───────── 手荷物 ───────── */}
      {step === "baggage" && (
        <section aria-labelledby="bag-h" className="flex flex-col gap-4">
          <h2 id="bag-h" className="text-base font-semibold">受託手荷物</h2>
          <Banner variant="default" icon={<IconLuggage className="h-4 w-4" />}>
            <span>お一人さま {freeBagsPerPax} 個（20kgまで）無料。超過分は1個 {yen(BAG_FEE_PER_EXTRA)}。</span>
          </Banner>

          {passengers.map((p) => (
            <Card key={p.id}>
              <CardContent className="flex items-center justify-between gap-3 p-4">
                <div className="min-w-0">
                  <div className="truncate font-medium">{p.name}</div>
                  <div className="text-xs text-muted-foreground">
                    {bags[p.id] > freeBagsPerPax
                      ? `超過 ${bags[p.id] - freeBagsPerPax} 個 / ${yen((bags[p.id] - freeBagsPerPax) * BAG_FEE_PER_EXTRA)}`
                      : "追加料金なし"}
                  </div>
                </div>
                <NumberInput
                  layout="stepper"
                  value={bags[p.id]}
                  min={0}
                  max={5}
                  onValueChange={(n) => setBags((b) => ({ ...b, [p.id]: n }))}
                  aria-label={`${p.name} の受託手荷物の個数`}
                  decrementLabel="手荷物を減らす"
                  incrementLabel="手荷物を増やす"
                />
              </CardContent>
            </Card>
          ))}

          <div className="rounded-lg border bg-card p-4">
            <h3 className="mb-3 text-sm font-semibold">お支払い内容</h3>
            <AmountBreakdown
              lines={amountLines}
              total={{ label: "追加料金 合計", amount: grandTotal }}
            />
          </div>
        </section>
      )}

      {/* ───────── 搭乗券 ───────── */}
      {step === "pass" && (
        <section aria-labelledby="pass-h" className="flex flex-col gap-4">
          <h2 id="pass-h" className="text-base font-semibold">搭乗券</h2>

          {/* StatusScreen は success バリアントを持たないため、成功は自前カードで表現 */}
          <div className="flex items-start gap-3 rounded-lg border border-success-border bg-success-subtle p-4 text-success-subtle-foreground">
            <IconShieldCheck className="mt-0.5 h-5 w-5 shrink-0" aria-hidden />
            <div>
              <p className="font-semibold">搭乗手続きが完了しました</p>
              <p className="text-sm">スマートフォンの画面をそのまま保安検査場・搭乗口でご提示ください。</p>
            </div>
          </div>

          {passengers.length > 1 ? (
            <Tabs
              value={passengers[passIndex]?.id}
              onValueChange={(v) =>
                setPassIndex(Math.max(0, passengers.findIndex((p) => p.id === v)))
              }
            >
              <TabsList className="w-full">
                {passengers.map((p) => (
                  <TabsTrigger key={p.id} value={p.id} className="flex-1">
                    {p.name.split(" ")[1] ?? p.name}
                  </TabsTrigger>
                ))}
              </TabsList>
              {passengers.map((p) => (
                <TabsContent key={p.id} value={p.id} className="px-0">
                  <BoardingPass flight={FLIGHT} passenger={p} />
                </TabsContent>
              ))}
            </Tabs>
          ) : (
            <BoardingPass flight={FLIGHT} passenger={passengers[0]} />
          )}

          <Card>
            <CardContent className="flex flex-col gap-3 p-4 text-sm">
              <div className="flex items-start gap-2">
                <IconShieldCheck className="mt-0.5 h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
                <span>保安検査場は <strong>{FLIGHT.securityClose}</strong> までにお通りください（{FLIGHT.terminal}）。</span>
              </div>
              <div className="flex items-start gap-2">
                <IconDoorEnter className="mt-0.5 h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
                <span>搭乗口 <strong>{FLIGHT.gate}</strong>・搭乗開始 <strong>{FLIGHT.boardingTime}</strong>。優先搭乗のご案内があります。</span>
              </div>
            </CardContent>
          </Card>
        </section>
      )}

      {/* ───────── 固定フッタ操作 ───────── */}
      {step !== "pass" ? (
        <div className="fixed inset-x-0 bottom-0 z-20 border-t bg-background/95 backdrop-blur">
          <div className="mx-auto flex w-full max-w-md items-center gap-3 px-4 py-3 sm:max-w-lg">
            {stepIndex > 0 && (
              <Button variant="outline" onClick={goBack} className="shrink-0">
                戻る
              </Button>
            )}
            <div className="flex flex-1 flex-col items-end leading-tight">
              {grandTotal > 0 && (
                <span className="text-xs text-muted-foreground">
                  追加料金 <span className="font-semibold text-foreground">{yen(grandTotal)}</span>
                </span>
              )}
            </div>
            <Button variant="primary" onClick={goNext} className="shrink-0">
              {step === "baggage" ? "チェックインを確定" : "次へ"}
            </Button>
          </div>
        </div>
      ) : (
        <div className="fixed inset-x-0 bottom-0 z-20 border-t bg-background/95 backdrop-blur">
          <div className="mx-auto flex w-full max-w-md items-center gap-3 px-4 py-3 sm:max-w-lg">
            <Button
              variant="primary"
              className="w-full"
              onClick={() => {
                setStep("confirm")
                setPassIndex(0)
              }}
            >
              予約の確認に戻る
            </Button>
          </div>
        </div>
      )}

      {/* ───────── 座席変更シート（下から） ───────── */}
      <Sheet
        open={seatSheetFor !== null}
        onOpenChange={(o) => {
          if (!o) {
            setSeatSheetFor(null)
            setDraftSeat(null)
          }
        }}
      >
        <SheetContent side="bottom" className="max-h-[90vh] overflow-y-auto">
          <SheetHeader>
            <SheetTitle className="flex items-center gap-2">
              <IconArmchair2 className="h-5 w-5" aria-hidden />
              座席の変更
            </SheetTitle>
            <SheetDescription>空席をタップして座席を選び直してください。</SheetDescription>
          </SheetHeader>
          {seatSheetFor && (
            <div className="mt-4">
              <SeatMap
                changingFor={seatSheetFor.name}
                ownSeats={ownSeats.filter((s) => s !== seatSheetFor.seat)}
                selectedId={draftSeat}
                onSelectSeat={setDraftSeat}
                onConfirm={confirmSeatChange}
                onCancel={() => {
                  setSeatSheetFor(null)
                  setDraftSeat(null)
                }}
              />
            </div>
          )}
        </SheetContent>
      </Sheet>
    </main>
  )
}

"use client"

import * as React from "react"
import { Badge, Button, cn } from "@gunjo/ui"
import {
  SEAT_ROWS,
  SEAT_COLS,
  SEAT_MAP,
  SEAT_TYPE_LABEL,
  AISLE_AFTER,
  colWindowLabel,
  yen,
  type SeatCell,
  type SeatType,
} from "./data"

// ─────────────────────────────────────────────────────────────────────────────
// HAND-ROLLED. @gunjo/ui has no SeatMap / selectable 2-D seat grid primitive.
// ScheduleGrid (role="grid") was the nearest candidate but cannot model an aisle
// gap, a persistent "selected" cell distinct from roving focus, or per-seat
// fee/type. So the grid itself is bespoke; only the legend chips (Badge) and the
// confirm action (Button) come from the kit.
// ─────────────────────────────────────────────────────────────────────────────

const TYPE_SWATCH: Record<SeatType, string> = {
  standard: "border-border bg-card",
  legroom: "border-info-border bg-info-subtle",
  exit: "border-warning-border bg-warning-subtle",
}

function seatVisualState(
  seat: SeatCell,
  selectedId: string | null,
  ownSeats: Set<string>,
) {
  if (seat.id === selectedId) return "selected" as const
  if (ownSeats.has(seat.id)) return "current" as const
  return seat.state // "available" | "occupied"
}

interface SeatButtonProps {
  seat: SeatCell
  visual: ReturnType<typeof seatVisualState>
  onSelect: (id: string) => void
}

function SeatButton({ seat, visual, onSelect }: SeatButtonProps) {
  const disabled = visual === "occupied"
  const isWindow = seat.col === "A" || seat.col === "F"
  const label =
    `${seat.id} ${SEAT_TYPE_LABEL[seat.type]} ${colWindowLabel(seat.id)}` +
    (seat.fee > 0 ? ` 追加${yen(seat.fee)}` : "") +
    (visual === "occupied"
      ? " 予約済み 選択できません"
      : visual === "current"
        ? " 現在のお座席"
        : visual === "selected"
          ? " 選択中"
          : " 空席")

  return (
    <button
      type="button"
      role="gridcell"
      aria-label={label}
      aria-pressed={visual === "selected"}
      aria-disabled={disabled || undefined}
      disabled={disabled}
      onClick={() => !disabled && onSelect(seat.id)}
      className={cn(
        "relative flex h-9 w-9 shrink-0 items-center justify-center rounded-md border text-[11px] font-semibold transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        // base by seat type
        TYPE_SWATCH[seat.type],
        // states layer on top
        visual === "available" &&
          "cursor-pointer text-foreground hover:border-primary hover:bg-primary/10",
        visual === "occupied" &&
          "cursor-not-allowed border-transparent bg-muted text-muted-foreground/60",
        visual === "current" &&
          "border-success-strong bg-success-subtle text-success-subtle-foreground ring-1 ring-success-strong",
        visual === "selected" &&
          "border-primary bg-primary text-primary-foreground ring-2 ring-primary",
        isWindow && "rounded-l-lg",
      )}
    >
      {visual === "occupied" ? (
        <span aria-hidden>×</span>
      ) : (
        <span aria-hidden>{seat.col}</span>
      )}
    </button>
  )
}

export interface SeatMapProps {
  /** 現在の自分たちの座席（緑表示・選択不可の確定席として扱う） */
  ownSeats: string[]
  /** 変更対象の搭乗者名（見出し用） */
  changingFor: string
  selectedId: string | null
  onSelectSeat: (id: string) => void
  onConfirm: () => void
  onCancel: () => void
}

export function SeatMap({
  ownSeats,
  changingFor,
  selectedId,
  onSelectSeat,
  onConfirm,
  onCancel,
}: SeatMapProps) {
  const ownSet = React.useMemo(() => new Set(ownSeats), [ownSeats])
  const selected = selectedId ? SEAT_MAP.find((s) => s.id === selectedId) : null

  const seatByRowCol = React.useMemo(() => {
    const m = new Map<string, SeatCell>()
    for (const s of SEAT_MAP) m.set(`${s.row}-${s.col}`, s)
    return m
  }, [])

  return (
    <div className="flex flex-col gap-4">
      <p className="text-sm text-muted-foreground">
        <span className="font-medium text-foreground">{changingFor}</span>{" "}
        さまの座席を選択してください。
      </p>

      {/* 凡例 — Badge は @gunjo/ui */}
      <div
        className="flex flex-wrap gap-2"
        role="list"
        aria-label="座席の凡例"
      >
        <Badge variant="outline" role="listitem">
          <span className="mr-1 inline-block h-3 w-3 rounded-sm border border-border bg-card" aria-hidden />
          普通席
        </Badge>
        <Badge variant="info" role="listitem">
          <span className="mr-1 inline-block h-3 w-3 rounded-sm border border-info-border bg-info-subtle" aria-hidden />
          足元ゆったり +¥1,500
        </Badge>
        <Badge variant="warning" role="listitem">
          <span className="mr-1 inline-block h-3 w-3 rounded-sm border border-warning-border bg-warning-subtle" aria-hidden />
          非常口 +¥1,000
        </Badge>
        <Badge variant="success" role="listitem">現在のお座席</Badge>
        <Badge variant="secondary" role="listitem">予約済み ×</Badge>
      </div>

      {/* 機首ラベル */}
      <div className="text-center text-[11px] font-medium uppercase tracking-widest text-muted-foreground">
        ◢ 機首 / FRONT ◣
      </div>

      {/* 座席グリッド本体 — role="grid" を手で付与 */}
      <div
        role="grid"
        aria-label={`${changingFor}さまの座席表`}
        className="mx-auto w-fit overflow-x-auto rounded-lg border bg-muted/30 p-3"
      >
        {/* 列ヘッダ */}
        <div role="row" className="mb-1 flex items-center gap-1.5">
          <span className="w-6 shrink-0" aria-hidden />
          {SEAT_COLS.map((col) => (
            <React.Fragment key={col}>
              <span
                role="columnheader"
                className="flex h-5 w-9 shrink-0 items-center justify-center text-[11px] font-medium text-muted-foreground"
              >
                {col}
              </span>
              {col === AISLE_AFTER && (
                <span className="w-5 shrink-0" aria-hidden />
              )}
            </React.Fragment>
          ))}
        </div>

        {SEAT_ROWS.map((row) => (
          <div role="row" key={row} className="mb-1.5 flex items-center gap-1.5">
            <span
              role="rowheader"
              className="w-6 shrink-0 text-right text-[11px] font-medium text-muted-foreground"
            >
              {row}
            </span>
            {SEAT_COLS.map((col) => {
              const seat = seatByRowCol.get(`${row}-${col}`)!
              return (
                <React.Fragment key={col}>
                  <SeatButton
                    seat={seat}
                    visual={seatVisualState(seat, selectedId, ownSet)}
                    onSelect={onSelectSeat}
                  />
                  {col === AISLE_AFTER && (
                    <span
                      className="flex w-5 shrink-0 items-center justify-center text-[9px] text-muted-foreground/50"
                      aria-hidden
                    >
                      ‖
                    </span>
                  )}
                </React.Fragment>
              )
            })}
          </div>
        ))}
      </div>

      {/* 選択中の確認バー */}
      <div
        className="rounded-lg border bg-card p-3"
        aria-live="polite"
      >
        {selected ? (
          <div className="flex flex-col gap-1">
            <div className="flex items-baseline justify-between gap-2">
              <span className="text-base font-semibold">
                {selected.id}{" "}
                <span className="text-sm font-normal text-muted-foreground">
                  {SEAT_TYPE_LABEL[selected.type]}・{colWindowLabel(selected.id)}
                </span>
              </span>
              <span className="text-sm font-semibold">
                {selected.fee > 0 ? `追加 ${yen(selected.fee)}` : "追加料金なし"}
              </span>
            </div>
          </div>
        ) : (
          <p className="text-sm text-muted-foreground">座席が選択されていません。</p>
        )}
      </div>

      <div className="flex gap-2">
        <Button variant="outline" className="flex-1" onClick={onCancel}>
          キャンセル
        </Button>
        <Button
          variant="primary"
          className="flex-1"
          disabled={!selected}
          onClick={onConfirm}
        >
          この席に変更
        </Button>
      </div>
    </div>
  )
}
